snippets.C0675:
-- C0675 · Migración simple (schema versioning) (Intermedio, Base de datos)
-- SQL Server: tabla de migraciones + migración idempotente v1
IF OBJECT_ID('dbo.schema_migrations','U') IS NULL
BEGIN
  CREATE TABLE dbo.schema_migrations (
    version NVARCHAR(50) NOT NULL PRIMARY KEY,
    applied_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME()
  );
END;

-- v1: crear tabla customers si no existe
IF OBJECT_ID('dbo.customers','U') IS NULL
BEGIN
  CREATE TABLE dbo.customers (
    id INT IDENTITY(1,1) PRIMARY KEY,
    name NVARCHAR(200) NOT NULL,
    email NVARCHAR(200) NULL
  );
END;

IF NOT EXISTS (SELECT 1 FROM dbo.schema_migrations WHERE version = 'v1')
  INSERT INTO dbo.schema_migrations(version) VALUES ('v1');

snippets.C0679:
-- C0679 · Deadlock/locking demo (2 sesiones) (Avanzado, Base de datos)
-- Ejecutar en 2 sesiones.
-- Pre:
-- IF OBJECT_ID('dbo.demo_lock','U') IS NULL
--   CREATE TABLE dbo.demo_lock(id int primary key, val int);
-- IF NOT EXISTS (SELECT 1 FROM dbo.demo_lock WHERE id=1)
--   INSERT INTO dbo.demo_lock(id,val) VALUES (1,10),(2,20);

-- SESIÓN A
BEGIN TRAN;
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 1;
  WAITFOR DELAY '00:00:03';
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 2;
COMMIT;

-- SESIÓN B
BEGIN TRAN;
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 2;
  WAITFOR DELAY '00:00:03';
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 1;
COMMIT;

-- Mitigación: mismo orden de locks (id asc), transacciones cortas, índices correctos,
-- y en algunos casos snapshot isolation.
